const files = $("Combine Extracted Content").all();
const combinedData = files.map((file) => file.json.data);

return [{ json: { data: combinedData } }];

const raw = items[0].json.output;

// Parse the JSON string returned by the agent
const data = JSON.parse(raw);

// Helper to convert arrays into bullet lists
function bulletList(arr, mapper = (x) => x) {
  if (!Array.isArray(arr)) return "";
  return arr.map(item => "• " + mapper(item)).join("\n");
}

// Build formatted fields
const formatted = {
  document_title: data.document_title || "",
  executive_summary: data.executive_summary || "",
  business_objective: data.business_objective || "",

  in_scope: bulletList(data.project_scope?.in_scope),
  out_of_scope: bulletList(data.project_scope?.out_of_scope),

  key_stakeholders: bulletList(
    data.key_stakeholders,
    s => `${s.name} — ${s.role}: ${s.responsibility}`
  ),

  milestones: bulletList(
    data.milestones,
    m => `${m.milestone} — ${m.success_criteria}`
  ),

  dependencies: bulletList(data.dependencies),

  assumptions: bulletList(data.assumptions),

  risks: bulletList(
    data.risks,
    r => `${r.risk} (Impact: ${r.impact}) — Mitigation: ${r.mitigation}`
  ),

  success_metrics: bulletList(data.success_metrics),

  next_steps: bulletList(data.next_steps),

  resource_plan: [
    data.resource_plan?.team_roles_needed?.length
      ? "Team Roles Needed:\n" + bulletList(data.resource_plan.team_roles_needed)
      : "",
    data.resource_plan?.tools_or_platforms_needed?.length
      ? "Tools or Platforms Needed:\n" + bulletList(data.resource_plan.tools_or_platforms_needed)
      : ""
  ].filter(Boolean).join("\n\n"),

  governance_and_communication: [
    data.governance_and_communication?.meeting_cadence
      ? `Meeting Cadence: ${data.governance_and_communication.meeting_cadence}`
      : "",
    data.governance_and_communication?.status_reporting
      ? `Status Reporting: ${data.governance_and_communication.status_reporting}`
      : "",
    data.governance_and_communication?.escalation_path
      ? `Escalation Path: ${data.governance_and_communication.escalation_path}`
      : ""
  ].filter(Boolean).join("\n\n")
};

return [{ json: formatted }];

let docItem = null;
let dataItem = null;

// Find doc item and formatted data item
for (const item of items) {
  if (item.json.documentId && item.json.body && item.json.body.content) {
    docItem = item.json;
  }

  if (
    item.json.executive_summary ||
    item.json.business_objective ||
    item.json.in_scope ||
    item.json.out_of_scope ||
    item.json.key_stakeholders ||
    item.json.project_phases ||
    item.json.milestones ||
    item.json.dependencies ||
    item.json.assumptions ||
    item.json.risks ||
    item.json.resource_plan ||
    item.json.governance_and_communication ||
    item.json.success_metrics ||
    item.json.next_steps
  ) {
    dataItem = item.json;
  }
}

if (!docItem) {
  throw new Error("Google Docs document structure not found in input.");
}

if (!dataItem) {
  throw new Error("Formatted project plan data not found in input.");
}

const documentId = docItem.documentId;
const content = docItem.body.content;
const docEndIndex = content[content.length - 1]?.endIndex;

// Map headings in the doc to formatted content
const replacements = {
  "Executive Summary": dataItem.executive_summary || "",
  "Business Objective": dataItem.business_objective || "",
  "In Scope": dataItem.in_scope || "",
  "Out of Scope": dataItem.out_of_scope || "",
  "Key Stakeholders": dataItem.key_stakeholders || "",
  "Project Phases": dataItem.project_phases || "",
  "Milestones": dataItem.milestones || "",
  "Dependencies": dataItem.dependencies || "",
  "Assumptions": dataItem.assumptions || "",
  "Risks": dataItem.risks || "",
  "Resource Plan": dataItem.resource_plan || "",
  "Governance and Communication": dataItem.governance_and_communication || "",
  "Success Metrics": dataItem.success_metrics || "",
  "Next Steps": dataItem.next_steps || ""
};

function getParagraphText(element) {
  if (!element?.paragraph?.elements) return "";
  return element.paragraph.elements
    .map(e => e.textRun?.content || "")
    .join("")
    .replace(/\n/g, "")
    .trim();
}

function isHeading(element) {
  const style = element?.paragraph?.paragraphStyle?.namedStyleType || "";
  return style.startsWith("HEADING");
}

const headings = [];

for (let i = 0; i < content.length; i++) {
  const el = content[i];
  if (el.paragraph && isHeading(el)) {
    headings.push({
      text: getParagraphText(el),
      startIndex: el.startIndex,
      endIndex: el.endIndex
    });
  }
}

function findSectionRange(headingText) {
  const idx = headings.findIndex(h => h.text === headingText);
  if (idx === -1) return null;

  const current = headings[idx];
  const next = headings[idx + 1];

  return {
    heading: headingText,
    startIndex: current.endIndex,
    endIndex: next ? next.startIndex : docEndIndex - 1
  };
}

function normalizeText(text) {
  return String(text || "")
    .replace(/\r\n/g, "\n")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

// Remove visible bullet symbol before insertion.
// We'll create real bullets later with createParagraphBullets.
function stripBulletMarkers(text) {
  return text
    .split("\n")
    .map(line => line.startsWith("• ") ? line.slice(2) : line)
    .join("\n");
}

// Find ranges of consecutive bullet paragraphs after stripping markers
function getBulletParagraphGroups(startIndex, originalText) {
  const lines = originalText.split("\n");
  const groups = [];

  let cursor = startIndex;
  let groupStart = null;
  let groupEnd = null;

  for (const line of lines) {
    const isBullet = line.startsWith("• ");
    const cleanedLine = isBullet ? line.slice(2) : line;
    const lineLengthAfterInsert = cleanedLine.length + 1; // + newline

    if (isBullet) {
      if (groupStart === null) groupStart = cursor;
      groupEnd = cursor + lineLengthAfterInsert;
    } else {
      if (groupStart !== null) {
        groups.push({ startIndex: groupStart, endIndex: groupEnd });
        groupStart = null;
        groupEnd = null;
      }
    }

    cursor += lineLengthAfterInsert;
  }

  if (groupStart !== null) {
    groups.push({ startIndex: groupStart, endIndex: groupEnd });
  }

  return groups;
}

const sections = Object.entries(replacements)
  .map(([heading, text]) => {
    const range = findSectionRange(heading);
    if (!range) return null;

    const normalizedOriginal = normalizeText(text);
    const cleanedText = stripBulletMarkers(normalizedOriginal);

    return {
      heading,
      originalText: normalizedOriginal,
      text: cleanedText,
      startIndex: range.startIndex,
      endIndex: range.endIndex
    };
  })
  .filter(Boolean)
  .sort((a, b) => b.startIndex - a.startIndex); // bottom-up

const requests = [];

for (const section of sections) {
  if (
    typeof section.startIndex === "number" &&
    typeof section.endIndex === "number" &&
    section.endIndex > section.startIndex
  ) {
    requests.push({
      deleteContentRange: {
        range: {
          startIndex: section.startIndex,
          endIndex: section.endIndex
        }
      }
    });
  }

  if (!section.text) continue;

  const insertedText = section.text + "\n";
  const insertedEndIndex = section.startIndex + insertedText.length;

  requests.push({
    insertText: {
      location: {
        index: section.startIndex
      },
      text: insertedText
    }
  });

  // Reset paragraph style completely to normal body text
  requests.push({
    updateParagraphStyle: {
      range: {
        startIndex: section.startIndex,
        endIndex: insertedEndIndex
      },
      paragraphStyle: {
        namedStyleType: "NORMAL_TEXT",
        lineSpacing: 115,
        spaceAbove: { magnitude: 0, unit: "PT" },
        spaceBelow: { magnitude: 0, unit: "PT" }
      },
      fields: "namedStyleType,lineSpacing,spaceAbove,spaceBelow"
    }
  });

  // Reset text style consistently
  requests.push({
    updateTextStyle: {
      range: {
        startIndex: section.startIndex,
        endIndex: insertedEndIndex
      },
      textStyle: {
        weightedFontFamily: {
          fontFamily: "Arial"
        },
        fontSize: {
          magnitude: 11,
          unit: "PT"
        },
        bold: false,
        italic: false,
        underline: false,
        strikethrough: false
      },
      fields: "weightedFontFamily,fontSize,bold,italic,underline,strikethrough"
    }
  });

  // Create real bullets for consecutive bullet paragraphs
  const bulletGroups = getBulletParagraphGroups(section.startIndex, section.originalText);

  for (const group of bulletGroups) {
    requests.push({
      createParagraphBullets: {
        range: {
          startIndex: group.startIndex,
          endIndex: group.endIndex
        },
        bulletPreset: "BULLET_DISC_CIRCLE_SQUARE"
      }
    });
  }
}

return [
  {
    json: {
      documentId,
      requests,
      updatedSections: sections.map(s => s.heading),
      foundHeadings: headings.map(h => h.text)
    }
  }
];
